#[derive(Debug, Clone, PartialEq, Eq)]
pub enum InventoryError {
    ItemNotFound,
    InsufficientStock { available: u32, requested: u32 },
}

pub fn process_order_concurrently(
    inventory: Arc<Inventory>,
    item_id: String,
    quantity: u32,
) -> std::thread::JoinHandle<Result<u32, InventoryError>> {
    std::thread::spawn(move || inventory.decrement_stock(&item_id, quantity))
}

